QString dataFilePath(const QString &username) {
    return DatabaseManager::getInstance()->dbPath() + "/profile_" + username + ".json";
}

bool DatabaseManager::saveData(const QString &username, const StudentProfile &profile)
{
    QFile file(dataFilePath(username));
    if (!file.open(QIODevice::WriteOnly)) return false;
    file.write(QJsonDocument(profile.toJson()).toJson());
    file.close();
    return true;
}

StudentProfile DatabaseManager::loadData(const QString &username)
{
    QFile file(dataFilePath(username));
    if (!file.open(QIODevice::ReadOnly)) return StudentProfile();
    StudentProfile sp = StudentProfile::fromJson(QJsonDocument::fromJson(file.readAll()).object());
    file.close();
    return sp;
}

bool DatabaseManager::exportBackup(const QString &filePath, QString &errorMsg)
{ Q_UNUSED(filePath); Q_UNUSED(errorMsg); return false; }
bool DatabaseManager::importBackup(const QString &filePath, QString &errorMsg)
{ Q_UNUSED(filePath); Q_UNUSED(errorMsg); return false; }